const body = $json;
if (body.benefit_type !== 'Sales_cycle_analyzer') return [{ json: { success: false, error_code: 'INVALID_INPUT', message: 'benefit_type must be Sales_cycle_analyzer' } }];
const averageCycleLength = Number(body.answers.average_cycle_length ?? body.answers.question_1 ?? 0);
const engineeringDelay = Number(body.answers.engineering_delay ?? body.answers.question_2 ?? 0);
const approvalTurnaround = Number(body.answers.approval_turnaround ?? body.answers.question_3 ?? 0);
if (![averageCycleLength, engineeringDelay, approvalTurnaround].every(Number.isFinite)) {
  return [{ json: { success: false, error_code: 'INVALID_INPUT', message: 'Cycle signals must be numeric' } }];
}
return [{ json: { ...body, cycle_inputs: { averageCycleLength, engineeringDelay, approvalTurnaround } } }];

if ($json.success === false) return [{ json: $json }];
const { averageCycleLength, engineeringDelay, approvalTurnaround } = $json.cycle_inputs;
const cycle_efficiency_score = Math.max(0, Math.min(100, Math.round(100 - (averageCycleLength * 0.5 + engineeringDelay * 1.2 + approvalTurnaround * 0.8))));
const delayValues = { Engineering: engineeringDelay, Approvals: approvalTurnaround, Sales_Process: averageCycleLength / 2 };
const delay_source = Object.keys(delayValues).reduce((a, b) => delayValues[a] > delayValues[b] ? a : b);
return [{ json: { ...$json, score: cycle_efficiency_score, delay_source } }];

if ($json.success === false) return [{ json: $json }];
return [{
  json: {
    success: true,
    benefit_type: 'Sales_cycle_analyzer',
    score: $json.score,
    summary: `Cycle efficiency score is ${$json.score}. Primary delay source: ${$json.delay_source}.`,
    recommendations: [
      'Introduce pre-approved configuration bundles for common deals.',
      'Define engineering response SLAs by opportunity tier.',
      'Automate approval escalations above threshold values.'
    ],
    meta: {
      execution_id: $execution.id,
      version: '1.0.0',
      benefit_version: '2026-Q1',
      cycle_efficiency_score: $json.score,
      delay_source: $json.delay_source
    }
  }
}];
